From 5e1bc6c9d8ed874baa4fc99500561c4e94c37d9d Mon Sep 17 00:00:00 2001
From: Sebastian Utz <su@rtme.net>
Date: Mon, 3 Feb 2025 16:54:15 +0100
Subject: [PATCH] Fix SubQueryResults.merge(), result values of both sides must
 be used

When merging 2 SubQueryResults, the result values of both sides
must be taken into account and merged.

Fixes #17307.
---
 docs/appendices/release-notes/5.10.1.rst      | 14 +++++
 .../planner/operators/SubQueryResults.java    | 26 ++++++---
 .../CorrelatedSubqueryITest.java              | 19 +++++-
 .../operators/SubQueryResultsTest.java        | 58 +++++++++++++++++++
 4 files changed, 107 insertions(+), 10 deletions(-)
 create mode 100644 server/src/test/java/io/crate/planner/operators/SubQueryResultsTest.java

diff --git a/docs/appendices/release-notes/5.10.1.rst b/docs/appendices/release-notes/5.10.1.rst
index 2b9a59093e..9f9f325fe2 100644
--- a/docs/appendices/release-notes/5.10.1.rst
+++ b/docs/appendices/release-notes/5.10.1.rst
@@ -74,3 +74,17 @@ Fixes
   ``ORDER BY`` and query had a ``LIMIT`` clause. Example.::

     SELECT a, b + ? as sum FROM tbl ORDER BY sum LIMIT 10
+
+- Fixed an issue that caused an error when using a correlated sub-query and
+  a normal subquery on the same level together with an additional sub-query on
+  an outer level. Example::
+
+    WITH tbl AS (SELECT 1 as x)
+    SELECT (
+      SELECT x FROM tbl
+      WHERE t.x = tbl.x
+        AND tbl.x IN (SELECT x FROM unnest([1]))
+    ),
+    (SELECT y FROM unnest([2]) as t2(y))
+    FROM tbl t
+
diff --git a/server/src/main/java/io/crate/planner/operators/SubQueryResults.java b/server/src/main/java/io/crate/planner/operators/SubQueryResults.java
index 57077b2404..832eee0345 100644
--- a/server/src/main/java/io/crate/planner/operators/SubQueryResults.java
+++ b/server/src/main/java/io/crate/planner/operators/SubQueryResults.java
@@ -22,6 +22,7 @@
 package io.crate.planner.operators;

 import java.util.Collections;
+import java.util.HashMap;
 import java.util.List;
 import java.util.Map;

@@ -46,11 +47,10 @@ public class SubQueryResults {
     private Row inputRow = Row.EMPTY;

     public SubQueryResults(Map<SelectSymbol, Object> valuesBySubQuery) {
-        this.valuesBySubQuery = valuesBySubQuery;
-        this.boundOuterColumns = EMPTY_OUTER_COLUMNS;
+        this(valuesBySubQuery, EMPTY_OUTER_COLUMNS);
     }

-    public SubQueryResults(Map<SelectSymbol, Object> valuesBySubQuery,
+    private SubQueryResults(Map<SelectSymbol, Object> valuesBySubQuery,
                            ObjectIntMap<OuterColumn> boundOuterColumns) {
         this.valuesBySubQuery = valuesBySubQuery;
         this.boundOuterColumns = boundOuterColumns;
@@ -90,7 +90,15 @@ public class SubQueryResults {
     }

     public static SubQueryResults merge(SubQueryResults subQueryResults1, SubQueryResults subQueryResults2) {
-        // Correlated subquery related fields.
+        // Correlated subquery related fields, expect only one of them to contain correlated subquery fields.
+        assert subQueryResults1.boundOuterColumns.isEmpty()
+            || subQueryResults2.boundOuterColumns.isEmpty()
+            : "Can't merge two SubQueryResults with non-empty boundOuterColumns";
+
+        assert subQueryResults1.inputRow.equals(Row.EMPTY)
+            || subQueryResults2.inputRow.equals(Row.EMPTY)
+            : "Can't merge two SubQueryResults with non-empty inputRow";
+
         Row mergedRow = subQueryResults1.inputRow;
         ObjectIntMap<OuterColumn> mergedBoundOuterColumns = subQueryResults1.boundOuterColumns;
         if (mergedRow.equals(Row.EMPTY)) {
@@ -100,11 +108,11 @@ public class SubQueryResults {
             mergedBoundOuterColumns = subQueryResults2.boundOuterColumns;
         }

-        // Regular sub-select field.
-        Map<SelectSymbol, Object> mergedValuesBySubQuery = subQueryResults1.valuesBySubQuery;
-        if (mergedValuesBySubQuery.isEmpty()) {
-            mergedValuesBySubQuery = subQueryResults2.valuesBySubQuery;
-        }
+        // Fully merge regular sub-select field.
+        Map<SelectSymbol, Object> mergedValuesBySubQuery = new HashMap<>();
+        mergedValuesBySubQuery.putAll(subQueryResults1.valuesBySubQuery);
+        mergedValuesBySubQuery.putAll(subQueryResults2.valuesBySubQuery);
+

         SubQueryResults combinedSubQueryResults = new SubQueryResults(mergedValuesBySubQuery, mergedBoundOuterColumns);
         combinedSubQueryResults.bindOuterColumnInputRow(mergedRow);
diff --git a/server/src/test/java/io/crate/integrationtests/CorrelatedSubqueryITest.java b/server/src/test/java/io/crate/integrationtests/CorrelatedSubqueryITest.java
index 5cdcf10d92..1e87b2ace1 100644
--- a/server/src/test/java/io/crate/integrationtests/CorrelatedSubqueryITest.java
+++ b/server/src/test/java/io/crate/integrationtests/CorrelatedSubqueryITest.java
@@ -446,7 +446,7 @@ public class CorrelatedSubqueryITest extends IntegTestCase {
      * Tests a bug https://github.com/crate/crate/issues/15398.
      */
     @Test
-    public void test_can_mix_correlated_qubquery_and_sub_select() {
+    public void test_can_mix_correlated_subquery_and_sub_select() {
         execute("CREATE TABLE tbl(x int)");
         execute("INSERT INTO tbl(x) VALUES (1)");
         execute("refresh table tbl");
@@ -462,6 +462,23 @@ public class CorrelatedSubqueryITest extends IntegTestCase {
         assertThat(response).hasRows("1");
     }

+    /*
+     * https://github.com/crate/crate/issues/17307
+     */
+    @Test
+    public void test_can_mix_correlated_subquery_and_sub_selects_with_sub_select() {
+        execute("""
+            WITH tbl AS (SELECT 1 as x)
+            SELECT (
+              SELECT x FROM tbl
+              WHERE t.x = tbl.x
+                AND
+                tbl.x IN (SELECT x FROM unnest([1]))
+            ), (SELECT y FROM unnest([2]) as t2(y))
+            FROM tbl t
+            """);
+        assertThat(response).hasRows("1| 2");
+    }

